## 4. HTML Viewer Architecture

**Single file, no external dependencies.** All CSS and JS is inline.

**Fetching strategy:** The viewer is served from the same directory as the `.jsonl` files. It fetches `/trace-index.json` (a generated manifest) and individual `.jsonl` files. However, since we do not want to generate a manifest file on every trace write, the viewer instead fetches a directory listing via a custom endpoint — but `http.server` doesn't support dynamic listing in JSON format.

**Better approach:** The viewer uses the fact that `http.server` returns an HTML directory listing when served from a directory. The viewer fetches `/` (the listing page), parses the `<a href>` links for `.jsonl` files, and then fetches those files individually. This is a known technique for consuming `http.server` listings without a manifest.

**Structure of the viewer HTML:**

```
<html>
  <head>
    <style>
      /* Full CSS inline — sidebar, timeline, swimlane */
      /* Color tokens: --green, --red, --blue, --orange, --gray */
    </style>
  </head>
  <body>
    <div id="sidebar">
      <!-- List of runs, populated by JS -->
    </div>
    <div id="main">
      <div id="toolbar">
        <!-- Search/filter input, auto-refresh toggle -->
      </div>
      <div id="timeline">
        <!-- Event rows rendered here -->
      </div>
    </div>
    <script>
      // All JS inline
    </script>
  </body>
</html>
```

**JS architecture (no framework):**

```javascript
// State
const state = {
  runs: [],          // [{filename, identifier, workspace, eventCount, firstTs, lastTs}]
  selected: null,    // filename of selected run
  events: [],        // parsed events for selected run
  filter: '',        // search string
  autoRefresh: false,
  refreshTimer: null
};

// Boot
async function init() {
  await loadRunList();
  // If URL hash specifies an identifier, select it
  const focus = location.hash.slice(1);
  if (focus) selectRun(focus);
  renderSidebar();
}

// Fetch directory listing, parse hrefs for .jsonl files
async function loadRunList() {
  const resp = await fetch('/');
  const html = await resp.text();
  // Parse <a href="...jsonl"> links
  const matches = [...html.matchAll(/href="([^"]+\.jsonl)"/g)];
  // For each, fetch first line to get metadata
  state.runs = await Promise.all(matches.map(async ([,filename]) => {
    const r = await fetch('/' + filename);
    const text = await r.text();
    const lines = text.trim().split('\n').filter(Boolean);
    const first = JSON.parse(lines[0] || '{}');
    const last = JSON.parse(lines[lines.length-1] || '{}');
    return {
      filename,
      identifier: first.identifier || filename,
      workspace: first.workspace || '',
      eventCount: lines.length,
      firstTs: first.ts,
      lastTs: last.ts,
      runId: first.run_id
    };
  }));
  // Sort newest first
  state.runs.sort((a,b) => (b.lastTs||'').localeCompare(a.lastTs||''));
}

async function selectRun(identifierOrFile) {
  // Find matching run
  const run = state.runs.find(r =>
    r.filename.includes(identifierOrFile) || r.identifier === identifierOrFile
  );
  if (!run) return;
  state.selected = run.filename;
  await loadEvents(run.filename);
  renderTimeline();
  if (state.autoRefresh) startAutoRefresh();
}

async function loadEvents(filename) {
  const resp = await fetch('/' + filename);
  const text = await resp.text();
  state.events = text.trim().split('\n')
    .filter(Boolean)
    .map(line => {
      try { return JSON.parse(line); }
      catch { return null; }
    })
    .filter(Boolean);
}

// Color coding by category
function eventColor(event) {
  if (event.endsWith('.passed') || event.endsWith('.completed') ||
      event === 'pr.created') return 'green';
  if (event.endsWith('.failed') || event === 'agent.blocked' ||
      event === 'agent.no_changes' || event === 'pr.creation_failed') return 'red';
  if (event.startsWith('orchestrat') || event.startsWith('subtask')) return 'purple';
  if (event.startsWith('ci.')) return 'orange';
  return 'blue';
}

// Render the timeline
function renderTimeline() {
  const container = document.getElementById('timeline');
  const filter = state.filter.toLowerCase();

  // Check if this is an orchestrated run (has subtask events)
  const hasSubtasks = state.events.some(e => e.event.startsWith('subtask.'));

  // Group events: main timeline + per-subtask swimlanes
  let html = '';

  if (hasSubtasks) {
    html += renderSwimlaneView();
  } else {
    html += renderFlatTimeline();
  }

  container.innerHTML = html;
  // Attach expand/collapse listeners
  container.querySelectorAll('.event-row').forEach(row => {
    row.addEventListener('click', () => row.classList.toggle('expanded'));
  });
}

function renderFlatTimeline() {
  const filter = state.filter.toLowerCase();
  const events = state.events.filter(e =>
    !filter || e.event.includes(filter) || JSON.stringify(e.data).toLowerCase().includes(filter)
  );

  return events.map(e => `
    <div class="event-row color-${eventColor(e.event)}">
      <span class="event-ts">${formatTs(e.ts)}</span>
      <span class="event-badge">${e.event}</span>
      <span class="event-summary">${summarize(e)}</span>
      <div class="event-detail">${formatData(e.data)}</div>
    </div>
  `).join('');
}

function renderSwimlaneView() {
  // Collect unique subtask identifiers from subtask.* events
  const subtaskIds = [...new Set(
    state.events
      .filter(e => e.event.startsWith('subtask.') && e.data?.identifier)
      .map(e => e.data.identifier)
  )];

  // Main orchestrator events (non-subtask-specific)
  const mainEvents = state.events.filter(e => !e.data?.identifier || !subtaskIds.includes(e.data.identifier));

  let html = `<div class="swimlane-container">`;
  html += `<div class="swimlane main-lane">
    <div class="swimlane-header">Orchestrator</div>
    ${mainEvents.map(renderEventRow).join('')}
  </div>`;

  for (const id of subtaskIds) {
    const events = state.events.filter(e =>
      e.data?.identifier === id || e.event === 'subtask.created' && e.data?.identifier === id
    );
    html += `<div class="swimlane">
      <div class="swimlane-header">${id}</div>
      ${events.map(renderEventRow).join('')}
    </div>`;
  }
  html += `</div>`;
  return html;
}

// Auto-refresh: poll every 5s
function startAutoRefresh() {
  clearInterval(state.refreshTimer);
  state.refreshTimer = setInterval(async () => {
    if (!state.selected) return;
    await loadEvents(state.selected);
    renderTimeline();
  }, 5000);
}
```

**Visual design:**
- Dark sidebar (gray-900), light main area
- Event rows: left border color indicates category (green/red/blue/orange/purple)
- Click to expand: shows raw `data` as indented JSON
- Timestamp shown as HH:MM:SS (relative time on hover via `title` attribute)
- Sidebar shows identifier, event count, relative time ("3 minutes ago")
- Search box filters by event name or data content in real time
- Auto-refresh toggle button (enabled by default when hash-focused on an identifier with a recent last event)

